    <div id="proyek-form-page">
      <div class="page-header flex-between">
        <div>
          <button class="btn btn-ghost btn-sm" onclick="window.navigate('proyek')" style="margin-bottom:8px">
            <i class="fas fa-arrow-left"></i> Kembali
          </button>
          <h1 class="page-title">${n?`Edit Proyek`:`Proyek SLF Baru`}</h1>
          <p class="page-subtitle">${n?`Perbarui data proyek pengkajian SLF`:`Isi data bangunan yang akan dikaji Sertifikat Laik Fungsinya`}</p>
        </div>
      </div>

      <form id="proyek-form" onsubmit="submitProyek(event)">
        <div style="display:grid;grid-template-columns:2fr 1fr;gap:var(--space-5)">

          <!-- Left Column -->
          <div style="display:flex;flex-direction:column;gap:var(--space-5)">

            <!-- Data Bangunan -->
            <div class="card">
              <div class="card-title" style="margin-bottom:var(--space-5)">
                <i class="fas fa-building" style="color:var(--brand-400);margin-right:8px"></i>
                Data Bangunan
              </div>

              <div class="form-group">
                <label class="form-label">Nama Bangunan <span class="required">*</span></label>
                <input type="text" class="form-input" name="nama_bangunan"
                       value="${r.nama_bangunan||``}" placeholder="Gedung Perkantoran XYZ" required />
              </div>

              <div class="grid-2">
                <div class="form-group">
                  <label class="form-label">Jenis Bangunan <span class="required">*</span></label>
                  <select class="form-select" name="jenis_bangunan" required>
                    <option value="">Pilih Jenis</option>
                    ${[`Bangunan Gedung`,`Hunian`,`Komersial`,`Industri`,`Pendidikan`,`Kesehatan`,`Ibadah`,`Pemerintahan`,`Campuran`].map(e=>`<option value="${e}" ${r.jenis_bangunan===e?`selected`:``}>${e}</option>`).join(``)}
                  </select>
                </div>
                <div class="form-group">
                  <label class="form-label">Konstruksi Utama</label>
                  <select class="form-select" name="jenis_konstruksi">
                    <option value="">Pilih Konstruksi</option>
                    ${[`Beton Bertulang`,`Baja`,`Kayu`,`Bata`,`Komposit`].map(e=>`<option value="${e}" ${r.jenis_konstruksi===e?`selected`:``}>${e}</option>`).join(``)}
                  </select>
                </div>
              </div>

              <div class="form-group">
                <label class="form-label">Alamat Lengkap <span class="required">*</span></label>
                <textarea class="form-textarea" name="alamat" rows="2" placeholder="Jl. Contoh No. 123, Kelurahan, Kecamatan, Kota" required>${r.alamat||``}</textarea>
              </div>

              <div class="grid-2">
                <div class="form-group">
                  <label class="form-label">Kota/Kabupaten</label>
                  <input type="text" class="form-input" name="kota" value="${r.kota||``}" placeholder="Jakarta Selatan" />
                </div>
                <div class="form-group">
                  <label class="form-label">Provinsi</label>
                  <input type="text" class="form-input" name="provinsi" value="${r.provinsi||``}" placeholder="DKI Jakarta" />
                </div>
              </div>
            </div>

            <!-- Data Teknis -->
            <div class="card">
              <div class="card-title" style="margin-bottom:var(--space-5)">
                <i class="fas fa-ruler-combined" style="color:var(--brand-400);margin-right:8px"></i>
                Data Teknis Bangunan
              </div>

              <div class="grid-2">
                <div class="form-group">
                  <label class="form-label">Luas Bangunan (m²)</label>
                  <input type="number" class="form-input" name="luas_bangunan" value="${r.luas_bangunan||``}" placeholder="1000" min="0" />
                </div>
                <div class="form-group">
                  <label class="form-label">Luas Lahan (m²)</label>
                  <input type="number" class="form-input" name="luas_lahan" value="${r.luas_lahan||``}" placeholder="2000" min="0" />
                </div>
              </div>

              <div class="grid-2">
                <div class="form-group">
                  <label class="form-label">Jumlah Lantai</label>
                  <input type="number" class="form-input" name="jumlah_lantai" value="${r.jumlah_lantai||``}" placeholder="5" min="1" />
                </div>
                <div class="form-group">
                  <label class="form-label">Tahun Dibangun</label>
                  <input type="number" class="form-input" name="tahun_dibangun" value="${r.tahun_dibangun||``}" placeholder="2000" min="1900" max="${new Date().getFullYear()}" />
                </div>
              </div>

              <div class="form-group">
                <label class="form-label">Nomor PBG / IMB</label>
                <input type="text" class="form-input" name="nomor_pbg" value="${r.nomor_pbg||``}" placeholder="No. IMB/PBG jika ada" />
                <span class="form-hint">Persetujuan Bangunan Gedung / Izin Mendirikan Bangunan</span>
              </div>

              <div class="form-group">
                <label class="form-label">Fungsi Utama Bangunan</label>
                <textarea class="form-textarea" name="fungsi_bangunan" rows="2" placeholder="Deskripsi fungsi utama bangunan...">${r.fungsi_bangunan||``}</textarea>
              </div>
            </div>

            <!-- Catatan / Kondisi Awal -->
            <div class="card">
              <div class="card-title" style="margin-bottom:var(--space-5)">
                <i class="fas fa-note-sticky" style="color:var(--brand-400);margin-right:8px"></i>
                Catatan Awal
              </div>
              <div class="form-group">
                <label class="form-label">Kondisi Umum Bangunan</label>
                <textarea class="form-textarea" name="kondisi_umum" rows="3" placeholder="Deskripsi kondisi umum bangunan saat ini...">${r.kondisi_umum||``}</textarea>
              </div>
              <div class="form-group">
                <label class="form-label">Catatan Khusus</label>
                <textarea class="form-textarea" name="catatan" rows="2" placeholder="Catatan tambahan untuk pengkaji...">${r.catatan||``}</textarea>
              </div>
            </div>
          </div>

          <!-- Right Column -->
          <div style="display:flex;flex-direction:column;gap:var(--space-5)">

            <!-- Pemilik -->
            <div class="card">
              <div class="card-title" style="margin-bottom:var(--space-5)">
                <i class="fas fa-user" style="color:var(--brand-400);margin-right:8px"></i>
                Data Pemilik / Pemohon
              </div>

              <div class="form-group">
                <label class="form-label">Nama Pemilik <span class="required">*</span></label>
                <input type="text" class="form-input" name="pemilik" value="${r.pemilik||``}" placeholder="PT Contoh atau Nama Pribadi" required />
              </div>
              <div class="form-group">
                <label class="form-label">Penanggung Jawab</label>
                <input type="text" class="form-input" name="penanggung_jawab" value="${r.penanggung_jawab||``}" placeholder="Nama PIC" />
              </div>
              <div class="form-group">
                <label class="form-label">Telepon / HP</label>
                <input type="tel" class="form-input" name="telepon" value="${r.telepon||``}" placeholder="08xx-xxxx-xxxx" />
              </div>
              <div class="form-group">
                <label class="form-label">Email</label>
                <input type="email" class="form-input" name="email_pemilik" value="${r.email_pemilik||``}" placeholder="email@domain.com" />
              </div>
            </div>

            <!-- Status SLF -->
            <div class="card">
              <div class="card-title" style="margin-bottom:var(--space-5)">
                <i class="fas fa-shield-halved" style="color:var(--brand-400);margin-right:8px"></i>
                Status SLF
              </div>

              <div class="form-group">
                <label class="form-label">Status Awal</label>
                <select class="form-select" name="status_slf">
                  ${i.statusSLF.map(e=>`
                    <option value="${e.value}" ${(r.status_slf||`DALAM_PENGKAJIAN`)===e.value?`selected`:``}>${e.label}</option>
                  `).join(``)}
                </select>
              </div>
              <div class="form-group">
                <label class="form-label">Tanggal Mulai Pengkajian</label>
                <input type="date" class="form-input" name="tanggal_mulai" value="${r.tanggal_mulai||new Date().toISOString().split(`T`)[0]}" />
              </div>
              <div class="form-group">
                <label class="form-label">Target Selesai</label>
                <input type="date" class="form-input" name="tanggal_target" value="${r.tanggal_target||``}" />
              </div>
            </div>

            <!-- AI Configuration -->
            <div class="ai-panel">
              <div class="ai-panel-header">
                <div class="ai-icon"><i class="fas fa-brain"></i></div>
                <div>
                  <div class="ai-panel-title">AI Engine</div>
                  <div class="ai-panel-subtitle">Konfigurasi analisis otomatis</div>
                </div>
              </div>
              <div class="form-group">
                <label class="form-label" style="color:hsla(258,60%,80%,0.8)">Fokus Analisis</label>
                <select class="form-select" name="ai_focus" style="background:hsla(0,0%,0%,0.3);border-color:hsla(258,60%,50%,0.3)">
                  <option value="komprehensif">Komprehensif (Semua Aspek)</option>
                  <option value="struktur">Prioritas Struktur</option>
                  <option value="kebakaran">Prioritas Keselamatan Kebakaran</option>
                  <option value="seismik">Analisis Seismik (ASCE 41-17)</option>
                </select>
              </div>
              <div class="ai-finding success">
                <i class="fas fa-circle-check" style="margin-right:6px"></i>
                AI Engine siap menganalisis setelah checklist diisi
              </div>
            </div>

            <!-- Submit -->
            <div style="display:flex;gap:var(--space-3)">
              <button type="submit" class="btn btn-primary" style="flex:1;padding:14px" id="btn-submit-proyek">
                <i class="fas ${n?`fa-save`:`fa-plus`}"></i>
                ${n?`Simpan Perubahan`:`Buat Proyek`}
              </button>
              ${n?``:`
                <button type="button" class="btn btn-secondary" style="padding:14px" id="btn-fill-sample" title="Isi Data Dummy" onclick="fillSampleData()">
                  <i class="fas fa-magic"></i>
                </button>
              `}
            </div>
          </div>
        </div>
      </form>
    </div>
